MAGs<-str_split('bin.10.ed bin_16_ctg8312 bin.17.ed bin.18.ed bin.1-polished bin.21.ed bin_22 alt_Areni bin.24.ed bin_6 CCAlphaproteobacteria_1 CCAlphaproteobacteria_2 CCAlphaproteobacteria_3 CCAlphaproteobacteria_4 CCAlphaproteobacteria_5 CCAlphaproteobacteria_6 CCAlphaproteobacteria_7 CCAmylibacter_sp_1 CCArcticimaribacter_sp_1 CCArenicellales_1 CCAzophilus_sp_1 CCAzotimanducaceae_1 CCAzotimanducaceae_2 CCAzotimanducaceae_3 CCBacteria_1 CCBalneolaceae_1 CCBdellovibrionales_1 CCBdellovibrionales_2 CCBdellovibrionales_3 CCBdellovibrionales_4 CCBdellovibrionales_5 CCBdellovibrionales_6 CCBdellovibrionales_7 CCBrevundimonas_sp_1 CCCaldilineaceae_1 CCCaldilineaceae_2 CCCoraliomargaritaceae_1 CCDehalococcoidia_1 CCDehalococcoidia_2 CCFlavobacteriaceae_1 CCFlavobacteriaceae_2 CCFlavobacteriaceae_3 CCFlavobacteriaceae_4 CCFlavobacteriaceae_5 CCFrancisellaceae_1 CCGammaproteobacteria_10 CCGammaproteobacteria_1 CCGammaproteobacteria_3 CCGammaproteobacteria_5 CCGammaproteobacteria_6 CCGammaproteobacteria_7 CCGammaproteobacteria_9 CCGeminicoccaceae_1 CCHellea_sp_1 CCHoeflea_sp_1 CCHyphomicrobiales_1 CCHyphomicrobiales_2 CCLeptospiria_1 CCLitorimonas_sp_1 CCLitorivicinaceae_1 CCLuminiphilus_sp_1 CCMariniblastus_sp_1 CCMarisimplicoccus_sp_1 CCMidichloriaceae_1 CCMultivorans_sp_1 CCNeptunochlamydia_sp_1 CCNitrosopumilus_sp_1 CCNitrosopumilus_sp_2 CCNitrospirales_1 CCNitrospirales_2 CCParacoccaceae_1 CCParacoccaceae_2 CCParacoccaceae_3 CCParacoccaceae_4 CCPhototrophicaceae_1 CCPoribacteria_1 CCPoribacteria_2 CCPorisulfidus_sp_1 CCPseudohongiella_sp_1 CCPseudohongiella_sp_2 CCPseudomonadales_1 CCRhizobiaceae_1 CCRhizobiaceae_2 CCRhizobiaceae_3 CCRhodococcus_qingshengii_1 CCRhodospirillales_1 CCRhodothermales_1 CCRickettsiaceae_1 CCRobiginitomaculum_sp_1 CCRubripirellula_sp_1 CCRubripirellula_sp_2 CCSchleiferiaceae_1 CCSilvanigrellaceae_1 CCSynechococcus_sp_1 CCSynoicihabitans_sp_1 CCTateyamaria_sp_1 CCThermodesulfobacteriota_1 CCVerrucomicrobiales_1 CCWoesearchaeota_archaeon_1',' ')
rela_l<-list()
for (v in versions){
  p<-paste('/srv/scratch/z5245780/Cymbastela_concentrica/Transcriptomic/',v,'/transcriptomic_reads_index_bowtie/',v,'_mapped_file.txt',sep='')
  map_idxstats_df<-read.table(p,header=TRUE,sep='\t',quote="",colClasses = c('character','numeric','numeric','numeric'))
  abund<-lapply(MAGs[[1]],function(mag){
    if (mag!='*'){
      map_individual_df<-map_idxstats_df[grepl(mag, map_idxstats_df$name),]
      normalised_mappedreads<-sum(map_individual_df$mapped_reads)/sum(map_individual_df$contig_length)
      return(setNames(normalised_mappedreads,mag))
    }
  })
  rela_abund<-unlist(lapply(abund,function(x) x/sum(unlist(abund))))
  rela_df<-data.frame(Sample=names(rela_abund),abundance=rela_abund)
  colnames(rela_df)[2] <- v
  rela_l[[v]] <- rela_df
}
merge_rela_df <- Reduce(function(x, y) merge(x, y, by="Sample", all=TRUE), rela_l)
merge_rela_df$Average<-apply(merge_rela_df[,2:ncol(merge_rela_df)],1,mean)
write.table(merge_rela_df,'Relative_abundance_041124.tsv',sep='\t',row.names=FALSE, quote=FALSE)

df_file<-read.table('Relative_abundance_041124.tsv',sep='\t',quote="",header=TRUE)

df<-df_file%>%pivot_longer(cols = -Sample,  # Columns to reshape (Sampling date)
             names_to = "Date",
             values_to = "Value")
df$Date<-sub('.*_','',df$Date)
ggplot(df,aes(x=Sample,y=Value,color=Date))+geom_point(size=ifelse(df$Date %in% c('Nanopore.sequencing', 'Pacbio.sequencing'), 3, 1.5))+
  scale_color_manual(values = c("red","green","#CC33FF","blue","pink","#FF9900","yellow","#669933","#33CCFF","#99FFCC","#996600","#660033","#996666", "#006666","#999999","#CCCCCC","#cc0066","black")) +
  theme_minimal() +theme(axis.text.x = element_text(angle = -90, hjust = 0,vjust = 0.3))+labs(x = "Mags", y = "Relative abundance",color="Data type")

df_file<-df_file[order(df_file$Average,decreasing = TRUE),]
